local GetName = game:GetService("MarketplaceService"):GetProductInfo(game.PlaceId)
local LocalPlayer = game.Players.LocalPlayer

getgenv().spamSoond = false
getgenv().stopsoun = false
getgenv().ka = false

-- i dont think this works
function stopSound()
    while getgenv().stopsoun == true do
        local class_check = game.IsA
        local sound = Instance.new("Sound")
        local sound_stop = sound:Destroy()
        local get_descendants = game.GetDescendants

        for i, v in next, get_descendants(game) do
            if class_check(v, "Sound") then
                sound_stop(v)
            end
        end

        get_descendants = nil
        sound:Remove()
        sound = nil
        get_descendants = nil
        sound_stop = nil
        task.wait()
    end
end

function spamSound()
    while getgenv().spamSoond == true do
        local class_check = game.IsA
        local sound = Instance.new("Sound")
        local sound_stop = sound.Play
        local get_descendants = game.GetDescendants

        for i, v in next, get_descendants(game) do
            if class_check(v, "Sound") then
                sound_stop(v)
            end
        end

        get_descendants = nil
        sound:Remove()
        get_descendants = nil
        sound_stop = nil
        task.wait()
    end
end

function killAura()
    spawn(
        function()
            while getgenv().ka == true do
                local Pop = game:GetService("Players"):GetPlayers()
                for _, player in next, game:GetService "Players":GetPlayers() do
                    if player ~= LocalPlayer then
                        local args = {[1] = player}
                        local Distance =
                            (player.Character:FindFirstChildOfClass("Part").Position -
                            LocalPlayer.Character:FindFirstChildOfClass("Part").Position).magnitude

                        if Distance <= 17 then
                            for player = 1, 25 do
                                game:GetService("ReplicatedStorage").meleeEvent:FireServer(unpack(args))
                            end
                        end
                    end
                end
                task.wait()
            end
        end
    )
end

