                )
            end

            function GetItem(Item, Ignore)
                local saved = LocalPlayer.Character:GetPrimaryPartCFrame()
                if
                    workspace.Prison_ITEMS.single:FindFirstChild(Item) and
                        workspace.Prison_ITEMS.single:FindFirstChild(Item):FindFirstChild("ITEMPICKUP")
                 then
                    Item = workspace.Prison_ITEMS.single:FindFirstChild(Item)
                    local ohInstance1 =
                        Item:FindFirstChildOfClass("Part") or Item:FindFirstChildOfClass("UnionOperation")
                    MoveTo(CFrame.new(ohInstance1.Position))
                    repeat
                        task.wait()
                        local ohInstance1 =
                            Item:FindFirstChildOfClass("Part") or Item:FindFirstChildOfClass("UnionOperation")
                        MoveTo(CFrame.new(ohInstance1.Position))
                        task.spawn(
                            function()
                                workspace.Remote.ItemHandler:InvokeServer(ohInstance1)
                            end
                        )
                        task.wait()
                    until plr.Backpack:FindFirstChild(Item.Name) or plr.Character:FindFirstChild(Item.Name)
                end
                if Ignore ~= true then
                    plr.Character:SetPrimaryPartCFrame(Ignore or saved)
                end
            end

            GetItem(v, true)
            task.wait(.25)
            LocalPlayer.Character.HumanoidRootPart.CFrame = currentCframe
        end
    }
)

